            AnalyticsDebugModule.shared.logAPIRequest(
                method: request.httpMethod ?? "UNKNOWN",
                url: url,
                headers: headers,
                body: body,
                userId: userId,
                email: email,
                token: token
            )
        }
    }

    public func didReceiveResponse(_ response: URLResponse, data: Data?, userId: String? = nil, email: String? = nil, token: String? = nil) {
