        AnalyticsDebugModule.shared.logAPIResponse(
            url: url,
            statusCode: httpResponse.statusCode,
            headers: httpResponse.allHeaderFields,
            body: data,
            userId: userId,
            email: email,
            token: token
        )
    }

    public func didFailRequest(_ request: URLRequest, error: Error, userId: String? = nil, email: String? = nil, token: String? = nil) {
        let urlString = request.url?.absoluteString ?? "unknown-url"
        AnalyticsDebugModule.shared.logErrorCondition(
